<script>
// Core initialization for modal-share.php; scope all selectors to the modal
(function () {
	const modalSelector = '#shareModal';
	const url = <?php echo json_encode($url); ?>;

	// Helper to (re)initialize modal share UI and events
	function initShareModal() {
		const modalEl = document.querySelector(modalSelector);
		if (!modalEl) return;

		// Always read the current URL directly - simplest and most reliable
		// This ensures we always have the exact current URL (base, issue, session, report)
		let shareUrl = window.location.origin + window.location.pathname;
		
		// Ensure URL ends with / for consistency
		if (!shareUrl.endsWith('/')) {
			shareUrl += '/';
		}
		
		// Store shareUrl in a way that both copy button and QR code can access the same value
		// Ensure we're using the final determined shareUrl for both
		const finalShareUrl = shareUrl;

		// Copy Link Button
		const copyBtn = modalEl.querySelector('#fiCopyLinkBtn');
		if (copyBtn) {
			// Remove old event listeners by cloning
			const newCopyBtn = copyBtn.cloneNode(true);
			copyBtn.parentNode.replaceChild(newCopyBtn, copyBtn);
			
			newCopyBtn.addEventListener('click', function () {
				navigator.clipboard.writeText(finalShareUrl).then(() => {
					const originalText = this.innerHTML;
					this.innerHTML = '<i class="bi bi-check"></i> Copied!';
					this.classList.add('btn-success');
					this.classList.remove('btn-outline-primary');
					setTimeout(() => {
						this.innerHTML = originalText;
						this.classList.remove('btn-success');
						this.classList.add('btn-outline-primary');
					}, 2000);
				});
			});
		}


		// Update social media share links
		const encodedUrl = encodeURIComponent(finalShareUrl);
		const socialLinks = modalEl.querySelectorAll('a[href*="intent/tweet"], a[href*="facebook.com/sharer"], a[href*="instagram.com/sharer"], a[href*="linkedin.com/sharing"]');
		socialLinks.forEach(function(link) {
			const href = link.getAttribute('href');
			if (href) {
				// Update URL parameter in href
				const newHref = href.replace(/[?&]url=[^&]*/, '') + (href.includes('?') ? '&' : '?') + 'url=' + encodedUrl;
				link.setAttribute('href', newHref);
			}
		});

		// Update email share link
		const emailLink = modalEl.querySelector('a[href^="mailto:"]');
		if (emailLink) {
			const href = emailLink.getAttribute('href');
			if (href) {
				// Extract subject and update body with new URL
				const subjectMatch = href.match(/subject=([^&]*)/);
				const subject = subjectMatch ? decodeURIComponent(subjectMatch[1]) : "Check out this legislator's Freedom Index";
				const originalBodyMatch = href.match(/body=([^&]*)/);
				let body = originalBodyMatch ? decodeURIComponent(originalBodyMatch[1]) : '';
				// Replace any existing URL in body with new share URL
				body = body.replace(/https?:\/\/[^\s]+/g, finalShareUrl);
				// If no body existed, create a simple one
				if (!originalBodyMatch) {
					body = 'Check out this page:\n\n' + finalShareUrl;
				}
				const newHref = 'mailto:?subject=' + encodeURIComponent(subject) + '&body=' + encodeURIComponent(body);
				emailLink.setAttribute('href', newHref);
			}
		}

		// QR Code - use the same finalShareUrl as the copy button
		const qrContainer = modalEl.querySelector('#fiQRCode');
		if (qrContainer) {
			// Remove existing QR code content if open/close
			qrContainer.innerHTML = '';
			if (typeof QRCodeStyling !== 'undefined') {
				const qrCode = new QRCodeStyling({
					width: 200,
					height: 200,
					type: "svg",
					data: finalShareUrl,
					margin: 4,
					qrOptions: { typeNumber: 0, mode: 'Byte', errorCorrectionLevel: 'M' },
					backgroundOptions: { color: "#ffffff" },
					dotsOptions: { color: "#000000", type: "rounded" }
				});
				qrCode.append(qrContainer);
			} else {
				const img = document.createElement('img');
				img.src = 'https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=' + encodeURIComponent(finalShareUrl);
				img.alt = 'QR Code';
				img.className = 'img-fluid';
				qrContainer.appendChild(img);
			}
		}
		
		// Update the displayed URL text below QR code to match the copy button URL
		const urlText = modalEl.querySelector('#fiQRCodeUrl');
		if (urlText) {
			urlText.textContent = finalShareUrl;
		}
	}

	// Show event: when modal opened, (re)initialize content
	const modalEl = document.querySelector(modalSelector);
	if (modalEl) {
		modalEl.addEventListener('shown.bs.modal', initShareModal);
	}

	// Direct run if modal is already visible/rendered
	if (modalEl && modalEl.classList.contains('show')) {
		initShareModal();
	}
})();
</script>